  ('social-worker-moex-07600', 'social-worker', 'social-worker-moex-099-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何者不是艾力克森（Erikson）的心理社會發展理論觀點？', '["每個人都要經歷所有發展的階段，沒有任何例外", "每個個體必須面對相同的任務及危機", "無論階段發展任務是否完成，個體都會被推進下一個階段", "只要能夠成功的完成上個階段的發展任務，下一個階段就可以不用再面對上個階段的課題"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "998532e9120f", "answer_pdf_sha1": "5c1028fd7619", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
